public boolean endOther(String a, String b) {
    // Convert both strings to lowercase for case-insensitive comparison
    a = a.toLowerCase();
    b = b.toLowerCase();

    // Get the lengths of the two strings
    int lenA = a.length();
    int lenB = b.length();

    // Check if b is at the end of a
    if (lenA >= lenB && a.substring(lenA - lenB).equals(b)) {
        return true;
    }

    // Check if a is at the end of b
    if (lenB >= lenA && b.substring(lenB - lenA).equals(a)) {
        return true;
    }

    return false;
}

public boolean endOther(String a, String b) {
    a = a.toLowerCase();
    b = b.toLowerCase();

    int aLen = a.length();
    int bLen = b.length();

    if (aLen == 0 || bLen == 0) {
        return false;
    }

    if (aLen >= bLen) {
        return a.endsWith(b);
    } else {
        return b.endsWith(a);
    }
}

public class FizzBuzzGenerator {
    public String[] fizzBuzz(int start, int end) {
        int size = end - start;
        String[] result = new String[size];

        for (int i = 0; i < size; i++) {
            int currentNum = start + i;

            if (currentNum % 3 == 0 && currentNum % 5 == 0) {
                result[i] = "FizzBuzz";
            } else if (currentNum % 3 == 0) {
                result[i] = "Fizz";
            } else if (currentNum % 5 == 0) {
                result[i] = "Buzz";
            } else {
                result[i] = String.valueOf(currentNum);
            }
        }

        return result;
    }

    public static void main(String[] args) {
        FizzBuzzGenerator fizzBuzzGenerator = new FizzBuzzGenerator();
        int start = 1;
        int end = 6;
        String[] output = fizzBuzzGenerator.fizzBuzz(start, end);

        System.out.print("[");
        for (int i = 0; i < output.length; i++) {
            System.out.print("\"" + output[i] + "\"");
            if (i < output.length - 1) {
                System.out.print(", ");
            }
        }
        System.out.println("]");
    }
}

