Code:
public int[] fix45(int[] nums) {
    int[] result = new int[nums.length];
    int index = 0;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 4) {
            result[i] = 4;
            result[i + 1] = 5;
        } else if (nums[i] != 5) {
            boolean found = false;
            for (int j = 0; j < nums.length; j++) {
                if (nums[j] == 5 && result[j] == 0) {
                    result[j] = nums[i];
                    found = true;
                    break;
                }
            }
            if (!found) {
                result[index] = nums[i];
                index++;
            }
        }
    }
    return result;
}

