public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int multiple = nums[0];
    boolean changed = false;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            multiple = nums[i];
            changed = true;
        } else if (changed) {
            nums[i] = multiple;
        }
    }

    return nums;
}

