public boolean xyBalance(String str) {
    int lastX = -1;
    int lastY = -1;

    for (int i = str.length() - 1; i >= 0; i--) {
        char c = str.charAt(i);

        if (c == 'x' && lastY > lastX) {
            lastX = i;
        } else if (c == 'y') {
            lastY = i;
        }
    }

    return lastY >= lastX;
}

