public int[] tenRun(int[] nums) {
    if (nums.length == 0) {
        return nums;
    }

    int multipleOf10 = nums[0];
    boolean setToMultipleOf10 = false;

    for (int i = 1; i < nums.length; i++) {
        if (nums[i] % 10 == 0) {
            multipleOf10 = nums[i];
            setToMultipleOf10 = true;
        } else if (setToMultipleOf10) {
            nums[i] = multipleOf10;
        }
    }

    return nums;
}

