public boolean twoTwo(int[] nums) {
    if (nums.length < 2) {
        return nums.length == 0 || nums[0] != 2;
    }

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            if (i > 0 && nums[i - 1] == 2) {
                continue;
            }
            if (i < nums.length - 1 && nums[i + 1] == 2) {
                i++;
                continue;
            }
            return false;
        }
    }

    return true;
}

