public String atFirst(String str) {
    if (str.length() >= 2) {
        return str.substring(0, 2);
    } else {
        String defaultChars = "@@";
        if (str.length() == 1) {
            return str + "@";
        } else {
            return defaultChars;
        }
    }
}

